import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle, Package, Zap, ArrowLeft, PartyPopper } from 'lucide-react';

export default function CreateListing() {
  const navigate = useNavigate();
  const [type, setType] = useState('item');
  const [showSuccess, setShowSuccess] = useState(false);

  const handlePublish = (e) => {
    e.preventDefault();
    
    // 1. Show the success popup
    setShowSuccess(true);

    // 2. Wait for 2 seconds, then redirect to Dashboard
    setTimeout(() => {
      setShowSuccess(false);
      navigate('/dashboard');
    }, 2500);
  };

  return (
    <div className="p-10 max-w-3xl mx-auto space-y-8 relative">
      {/* Back Button */}
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-slate-400 font-bold hover:text-teal-600 transition-all">
        <ArrowLeft size={20} /> Back
      </button>

      <div>
        <h1 className="text-4xl font-black text-slate-900">Create New Listing</h1>
        <p className="text-slate-500 font-medium mt-2">Share a resource or skill with the Kochi community.</p>
      </div>

      <div className="bg-white rounded-[40px] p-10 shadow-sm border border-slate-50 space-y-8">
        {/* Toggle Switch */}
        <div className="flex bg-slate-50 p-1.5 rounded-2xl gap-2">
          <button 
            onClick={() => setType('item')} 
            className={`flex-1 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${type === 'item' ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-400'}`}
          >
            <Package size={18} /> Physical Item
          </button>
          <button 
            onClick={() => setType('skill')} 
            className={`flex-1 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${type === 'skill' ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-400'}`}
          >
            <Zap size={18} /> Professional Skill
          </button>
        </div>

        {/* Form Fields */}
        <form onSubmit={handlePublish} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Title</label>
            <input required placeholder="e.g. Professional Camera or Piano Lessons" className="w-full p-6 bg-slate-50 rounded-2xl outline-none ring-2 ring-transparent focus:ring-teal-500 font-bold" />
          </div>
          
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Token Value (WTK)</label>
              <input required type="number" placeholder="50" className="w-full p-6 bg-slate-50 rounded-2xl outline-none ring-2 ring-transparent focus:ring-teal-500 font-bold" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Location</label>
              <input required placeholder="Kochi" className="w-full p-6 bg-slate-50 rounded-2xl outline-none ring-2 ring-transparent focus:ring-teal-500 font-bold" />
            </div>
          </div>

          <button 
            type="submit" 
            className="w-full bg-teal-600 text-white py-6 rounded-2xl font-black text-lg hover:bg-teal-700 transition-all flex items-center justify-center gap-3 shadow-lg shadow-teal-600/20"
          >
            Publish Listing <CheckCircle size={22} />
          </button>
        </form>
      </div>

      {/* SUCCESS POPUP MODAL */}
      <AnimatePresence>
        {showSuccess && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm">
            <motion.div 
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.8, opacity: 0 }}
              className="bg-white p-12 rounded-[50px] shadow-2xl text-center max-w-sm w-full border border-teal-100"
            >
              <div className="w-24 h-24 bg-teal-50 text-teal-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <PartyPopper size={48} className="animate-bounce" />
              </div>
              <h2 className="text-3xl font-black text-slate-900 mb-2">Success!</h2>
              <p className="text-slate-500 font-medium">Your listing has been published to the community.</p>
              
              <div className="mt-8 w-full bg-slate-100 h-1 rounded-full overflow-hidden">
                <motion.div 
                  initial={{ width: "0%" }}
                  animate={{ width: "100%" }}
                  transition={{ duration: 2.2 }}
                  className="h-full bg-teal-600"
                />
              </div>
              <p className="text-[10px] font-black text-slate-300 mt-4 uppercase tracking-widest">Redirecting to Dashboard...</p>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}
